+func TestConfig_Validate(t *testing.T) {
+	tests := []struct {
+		mode    Mode
+		wantErr bool
+	}{
+		{ModeOff, false},
+		{ModeWarn, false},
+		{ModeRedact, false},
+		{ModeBlock, false},
+		{"invalid", true},
+		{"", true},
+	}
+
+	for _, tt := range tests {
+		t.Run(string(tt.mode), func(t *testing.T) {
+			cfg := Config{Mode: tt.mode}
+			err := cfg.Validate()
+			if (err != nil) != tt.wantErr {
+				t.Errorf("Validate() error = %v, wantErr %v", err, tt.wantErr)
+			}
+		})
+	}
+}
